<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Personal Expense Tracker</title>
    <style>
        :root {
            --primary: #2563eb;
            --danger: #dc2626;
            --bg: #f8fafc;
            --surface: #ffffff;
            --text: #1e293b;
            --border: #e2e8f0;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg);
            color: var(--text);
            margin: 0;
            padding: 20px;
            line-height: 1.5;
        }

        .container {
            max-width: 600px;
            margin: 0 auto;
            background: var(--surface);
            padding: 2rem;
            border-radius: 8px;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
        }

        h1 { margin-top: 0; font-size: 1.5rem; text-align: center; }

        /* Form Styles */
        .form-group { margin-bottom: 1rem; }
        label { display: block; margin-bottom: 0.25rem; font-weight: 600; font-size: 0.9rem; }

        input, select {
            width: 100%;
            padding: 0.5rem;
            border: 1px solid var(--border);
            border-radius: 4px;
            font-size: 1rem;
            box-sizing: border-box; /* Ensures padding doesn't affect width */
        }

        button {
            cursor: pointer;
            border: none;
            border-radius: 4px;
            font-weight: 600;
            transition: opacity 0.2s;
        }

        button:hover { opacity: 0.9; }

        #add-expense {
            background-color: var(--primary);
            color: white;
            width: 100%;
            padding: 0.75rem;
            font-size: 1rem;
        }

        #form-error {
            color: var(--danger);
            font-size: 0.875rem;
            margin-top: 0.25rem;
            min-height: 1.2em; /* Reserve space */
        }

        /* Filters */
        .filters {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
            gap: 1rem;
            margin-bottom: 1.5rem;
            padding-top: 1rem;
            border-top: 1px solid var(--border);
        }

        /* Summary */
        .summary {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 1.5rem;
            padding-bottom: 1rem;
            border-bottom: 1px solid var(--border);
        }

        #total { font-size: 1.25rem; font-weight: bold; color: var(--primary); }

        .cat-totals { display: flex; gap: 1rem; flex-wrap: wrap; margin-top: 0.5rem; }
        .cat-total { 
            background: #eff6ff; 
            padding: 0.25rem 0.5rem; 
            border-radius: 4px; 
            font-size: 0.875rem; 
            color: var(--primary);
            border: 1px solid #dbeafe;
        }

        /* List */
        #expense-list { list-style: none; padding: 0; margin: 0; }

        .expense {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 0.75rem;
            border-bottom: 1px solid var(--border);
            font-size: 0.95rem;
        }

        .expense:last-child { border-bottom: none; }

        .expense-info { display: flex; flex-direction: column; gap: 0.25rem; }
        .expense-amount { font-weight: bold; color: var(--text); }
        .expense-meta { font-size: 0.8rem; color: #64748b; }

        .exp-del {
            background-color: transparent;
            color: var(--danger);
            padding: 0.25rem 0.5rem;
            font-size: 0.85rem;
            border: 1px solid transparent;
        }

        .exp-del:hover {
            background-color: #fef2f2;
            text-decoration: underline;
        }

        /* Utility */
        .hidden { display: none !important; }
    </style>
</head>
<body>

<div class="container">
    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <form id="expense-form">
        <div class="form-group">
            <label for="amount">Amount ($)</label>
            <input type="number" id="amount" step="0.01" min="0.01" placeholder="e.g. 25.50" required>
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <select id="category" required>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>

        <div class="form-group">
            <label for="date">Date</label>
            <input type="date" id="date" required>
        </div>

        <div class="form-group">
            <label for="note">Note (Optional)</label>
            <input type="text" id="note" placeholder="e.g. Weekly shopping">
        </div>

        <button type="submit" id="add-expense">Add Expense</button>
        <div id="form-error"></div>
    </form>

    <!-- Filters -->
    <div class="filters">
        <div>
            <label for="filter-category">Category</label>
            <select id="filter-category">
                <option value="all">All Categories</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>
        <div>
            <label for="filter-from">From Date</label>
            <input type="date" id="filter-from">
        </div>
        <div>
            <label for="filter-to">To Date</label>
            <input type="date" id="filter-to">
        </div>
    </div>

    <!-- Summary -->
    <div class="summary">
        <span>Total (Visible): <span id="total">$0.00</span></span>
        <div class="cat-totals" id="cat-totals-container">
            <!-- Category totals injected here -->
        </div>
    </div>

    <!-- List -->
    <ul id="expense-list"></ul>
</div>

<script>
    // --- State Management ---
    let expenses = [];

    // --- DOM Elements ---
    const form = document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categorySelect = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const addBtn = document.getElementById('add-expense');
    const errorDiv = document.getElementById('form-error');

    // Filter Elements
    const filterCategory = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');

    // List & Summary Elements
    const listContainer = document.getElementById('expense-list');
    const totalDisplay = document.getElementById('total');
    const catTotalsContainer = document.getElementById('cat-totals-container');

    // --- Initialization ---
    function init() {
        loadFromStorage();
        setupEventListeners();
        render();

        // Set default date to today for convenience
        dateInput.valueAsDate = new Date();
    }

    // --- Core Logic ---

    function saveToStorage() {
        localStorage.setItem('expenses', JSON.stringify(expenses));
    }

    function loadFromStorage() {
        const stored = localStorage.getItem('expenses');
        if (stored) {
            expenses = JSON.parse(stored);
        }
    }

    function setupEventListeners() {
        form.addEventListener('submit', handleFormSubmit);

        // Filter listeners to trigger immediate re-render
        filterCategory.addEventListener('change', render);
        filterFrom.addEventListener('change', render);
        filterTo.addEventListener('change', render);
    }

    function handleFormSubmit(e) {
        e.preventDefault();

        // Validation Logic
        const amountVal = parseFloat(amountInput.value);
        const dateVal = dateInput.value;

        let errorMessage = "";

        if (!amountVal || isNaN(amountVal)) {
            errorMessage = "Please enter a valid number.";
        } else if (amountVal <= 0) {
            errorMessage = "Amount must be greater than zero.";
        } else if (!dateVal) {
            errorMessage = "Please select a date.";
        }

        if (errorMessage) {
            errorDiv.textContent = errorMessage;
            return; // Stop execution
        }

        // Success: Clear error and reset amount field as requested
        errorDiv.textContent = "";
        amountInput.value = ""; 

        // Create Expense Object
        const newExpense = {
            id: Date.now(), // Simple unique ID
            amount: amountVal,
            category: categorySelect.value,
            date: dateVal,
            note: noteInput.value.trim() || ""
        };

        expenses.push(newExpense);

        // Save and Render
        saveToStorage();
        render();
    }

    function deleteExpense(id) {
        // Remove immediately from array
        expenses = expenses.filter(exp => exp.id !== id);
        saveToStorage();
        render();
    }

    // --- Rendering Logic ---

    function render() {
        // 1. Get Filter Values
        const filterCat = filterCategory.value;
        const filterFromVal = filterFrom.value;
        const filterToVal = filterTo.value;

        // 2. Filter Expenses
        let filteredExpenses = expenses.filter(exp => {
            // Category Filter
            if (filterCat !== 'all' && exp.category !== filterCat) return false;

            // Date Range Filter
            if (filterFromVal && new Date(exp.date) < new Date(filterFromVal)) return false;
            if (filterToVal && new Date(exp.date) > new Date(filterToVal)) return false;

            return true;
        });

        // 3. Sort: Newest first (descending date)
        filteredExpenses.sort((a, b) => new Date(b.date) - new Date(a.date));

        // 4. Render List
        listContainer.innerHTML = '';

        if (filteredExpenses.length === 0) {
            listContainer.innerHTML = '<li style="text-align:center; color:#64748b;">No expenses found.</li>';
        } else {
            filteredExpenses.forEach(exp => {
                const li = document.createElement('li');
                li.className = 'expense';

                // Format Date nicely (YYYY-MM-DD -> MM/DD/YYYY)
                const dateObj = new Date(exp.date);
                const formattedDate = dateObj.toLocaleDateString();

                li.innerHTML = `
                    <div class="expense-info">
                        <span class="expense-amount">$${exp.amount.toFixed(2)}</span>
                        <span class="expense-meta">${exp.category} • ${formattedDate}</span>
                        ${exp.note ? `<span style="font-style:italic; color:#94a3b8;">"${exp.note}"</span>` : ''}
                    </div>
                    <button class="exp-del" onclick="deleteExpense(${exp.id})">Delete</button>
                `;
                listContainer.appendChild(li);
            });
        }

        // 5. Calculate Totals (Visible only)
        const totalAmount = filteredExpenses.reduce((sum, exp) => sum + exp.amount, 0);

        // Update Total Display
        totalDisplay.textContent = `$${totalAmount.toFixed(2)}`;

        // Update Category Totals
        catTotalsContainer.innerHTML = '';

        // Get unique categories present in the filtered list
        const visibleCategories = [...new Set(filteredExpenses.map(e => e.category))];

        visibleCategories.forEach(cat => {
            const catSum = filteredExpenses
                .filter(e => e.category === cat)
                .reduce((sum, e) => sum + e.amount, 0);

            const div = document.createElement('div');
            div.className = 'cat-total';
            div.setAttribute('data-cat', cat);
            div.textContent = `${cat.charAt(0).toUpperCase() + cat.slice(1)}: $${catSum.toFixed(2)}`;

            catTotalsContainer.appendChild(div);
        });
    }

    // Run on load
    init();

</script>
</body>
</html>
